{"type": "email", "id": "email_001", "subject": "Weekly Team Meeting Schedule Confirmation", "from": "sophie.tran@leesmarket.com", "from_name": "Sophie Tran", "to": ["mike.chen@leesmarket.com", "jessica.liu@leesmarket.com", "kevin.patel@leesmarket.com", "sarah.wong@leesmarket.com"], "cc": [], "date": "2023-02-10 09:00:00", "body": "Hello Team,

