{"type": "email", "id": "email_003", "subject": "New SOPs Implementation Update", "from": "sophie.tran@leesmarket.com", "from_name": "Sophie Tran", "to": ["mike.chen@leesmarket.com", "jessica.liu@leesmarket.com", "kevin.patel@leesmarket.com", "sarah.wong@leesmarket.com"], "cc": [], "date": "2023-02-20 12:00:00", "body": "Hello Team,

